module UART_RX(CLK, RST, RX_IN, Prescale, PAR_EN, PAR_TYP, data_valid,
     P_DATA, parity_error, framing_error);
  input CLK, RST, RX_IN, PAR_EN, PAR_TYP;
  input [5:0] Prescale;
  output data_valid, parity_error, framing_error;
  output [7:0] P_DATA;
  wire CLK, RST, RX_IN, PAR_EN, PAR_TYP;
  wire [5:0] Prescale;
  wire data_valid, parity_error, framing_error;
  wire [7:0] P_DATA;
  wire [4:0] edge_cnt;
  wire [3:0] bit_cnt;
  wire UNCONNECTED18, UNCONNECTED_HIER_Z22, UNCONNECTED_HIER_Z23,
       dat_samp_en, deser_en, par_chk_en, sampled_bit, stp_chk_en;
  wire strt_chk_en, strt_glitch;
  UART_RX_FSM U0_FSM(.CLK (CLK), .RST (RST), .RX_IN (RX_IN), .PAR_EN
       (PAR_EN), .Prescale (Prescale), .edge_cnt (edge_cnt), .bit_cnt
       (bit_cnt), .par_err (parity_error), .strt_glitch (strt_glitch),
       .stp_err (framing_error), .dat_samp_en (dat_samp_en), .enable
       (UNCONNECTED18), .deser_en (deser_en), .stp_chk_en (stp_chk_en),
       .strt_chk_en (strt_chk_en), .par_chk_en (par_chk_en),
       .data_valid (data_valid));
  UART_RX_data_sampling U0_data_sampling(.CLK (CLK), .RST (RST), .RX_IN
       (RX_IN), .Prescale (Prescale), .dat_samp_en (dat_samp_en),
       .edge_cnt (edge_cnt), .sampled_bit (sampled_bit));
  UART_RX_deserializer U0_deserializer(.CLK (CLK), .RST (RST), .bit_cnt
       (bit_cnt), .deser_en (deser_en), .sampled_bit (sampled_bit),
       .P_DATA (P_DATA));
  UART_RX_edge_bit_counter U0_edge_bit_counter(.CLK (CLK), .RST (RST),
       .Prescale (Prescale), .PAR_EN (UNCONNECTED_HIER_Z22), .enable
       (dat_samp_en), .bit_cnt (bit_cnt), .edge_cnt (edge_cnt));
  UART_RX_parity_check U0_parity_check(.CLK (CLK), .RST (RST), .RX_IN
       (UNCONNECTED_HIER_Z23), .PAR_TYP (PAR_TYP), .Prescale
       (Prescale), .edge_cnt (edge_cnt), .bit_cnt (bit_cnt),
       .par_chk_en (par_chk_en), .sampled_bit (sampled_bit), .P_DATA
       (P_DATA), .par_err (parity_error));
  UART_RX_stop_check U0_stop_check(.CLK (CLK), .RST (RST), .Prescale
       (Prescale), .edge_cnt (edge_cnt), .stp_chk_en (stp_chk_en),
       .sampled_bit (sampled_bit), .stp_err (framing_error));
  UART_RX_strt_check U0_strt_check(.CLK (CLK), .RST (RST), .strt_chk_en
       (strt_chk_en), .Prescale (Prescale), .edge_cnt (edge_cnt),
       .bit_cnt (bit_cnt), .sampled_bit (sampled_bit), .strt_glitch
       (strt_glitch));
endmodule

module UART_TX_FSM(Data_Valid, PAR_EN, ser_done, CLK, RST, ser_en,
     mux_sel, busy);
  input Data_Valid, PAR_EN, ser_done, CLK, RST;
  output ser_en, busy;
  output [1:0] mux_sel;
  wire Data_Valid, PAR_EN, ser_done, CLK, RST;
  wire ser_en, busy;
  wire [1:0] mux_sel;
  wire [2:0] current_state;
  wire n_0, n_1, n_3, n_4, n_5, n_7, n_16, n_18;
  NOR2BX1 g209(.AN (n_16), .B (current_state[2]), .Y (busy));
  NOR2BX1 g210(.AN (current_state[1]), .B (current_state[2]), .Y
       (mux_sel[1]));
  NOR2BX1 g211(.AN (current_state[0]), .B (current_state[2]), .Y
       (ser_en));
  OR2X1 g212(.A (current_state[0]), .B (current_state[1]), .Y (n_16));
  DFFRHQX1 \current_state_reg[0] (.RN (RST), .CK (CLK), .D (n_7), .Q
       (current_state[0]));
  OAI22X1 g262(.A0 (current_state[2]), .A1 (n_18), .B0 (ser_done), .B1
       (n_4), .Y (n_7));
  DFFRHQX1 \current_state_reg[2] (.RN (RST), .CK (CLK), .D (n_5), .Q
       (current_state[2]));
  AOI21X1 g265(.A0 (current_state[0]), .A1 (n_3), .B0 (n_1), .Y (n_5));
  NAND2BX1 g267(.AN (PAR_EN), .B (ser_done), .Y (n_3));
  NAND2X1 g268(.A (current_state[0]), .B (mux_sel[1]), .Y (n_4));
  INVX1 g270(.A (mux_sel[1]), .Y (n_1));
  DFFRX1 \current_state_reg[1] (.RN (RST), .CK (CLK), .D (busy), .Q
       (current_state[1]), .QN (n_0));
  MXI2XL g274(.A (Data_Valid), .B (n_0), .S0 (n_16), .Y (n_18));
endmodule

